SELECT pollster_id, COUNT(poll_id) as poll_count
FROM polls
GROUP BY pollster_id;

SELECT tag_name
FROM poll_tags
WHERE poll_id = 0;

SELECT COUNT(*) AS total_tags
FROM poll_tags
WHERE poll_id = 0;

SELECT pollster_name
FROM pollsters
WHERE pollster_id IN (SELECT pollster_id FROM pollster_polls);

SELECT pollster_name
FROM pollsters
ORDER BY pollster_name ASC;

SELECT category_name
FROM question_categories
WHERE category_id = 1;

SELECT COUNT(DISTINCT pollster_id) AS active_pollster_count
FROM polls
WHERE is_active = 1;
